"use client";

import Link from "next/link";
import { useEffect, useState } from "react";
import type { HeroSlide, SiteSettings } from "@/lib/content-data";

export function HomeHero({ slides, settings }: { slides: HeroSlide[]; settings: SiteSettings }) {
  const [active, setActive] = useState(0);
  useEffect(() => {
    if (slides.length < 2) return;
    const timer = window.setInterval(() => setActive((current) => (current + 1) % slides.length), 6500);
    return () => window.clearInterval(timer);
  }, [slides.length]);

  return <section className="hero">
    <div className="hero-media" aria-live="off">
      {slides.map((slide, index) => <img className={`hero-slide${index === active ? " active" : ""}`} key={slide.id} src={slide.imageUrl} alt={slide.altText} loading={index === 0 ? "eager" : "lazy"} />)}
      <div className="hero-overlay" />
    </div>
    {slides[active]?.altText && <p className="hero-slide-caption" key={slides[active].id} aria-live="polite">{slides[active].altText}</p>}
    <div className="hero-content">
      <p className="eyebrow light"><span>01</span>{settings.heroEyebrow}</p>
      <h1>{settings.heroTitleTop}<br /><em>{settings.heroTitleAccent}</em><br />{settings.heroTitleBottom}</h1>
      <div className="hero-bottom">
        <p>{settings.heroDescription}</p>
        <Link href="/projeler" className="round-link" aria-label="Projeleri incele"><span>Projeleri<br />inceleyin</span><b>↗</b></Link>
      </div>
    </div>
    {slides.length > 1 && <div className="slider-controls" aria-label="Ana sayfa görsel slaytı">
      <button type="button" onClick={() => setActive((active - 1 + slides.length) % slides.length)} aria-label="Önceki görsel">←</button>
      <div>{slides.map((slide, index) => <button type="button" className={index === active ? "active" : ""} key={slide.id} onClick={() => setActive(index)} aria-label={`${index + 1}. görseli göster`} />)}</div>
      <button type="button" onClick={() => setActive((active + 1) % slides.length)} aria-label="Sonraki görsel">→</button>
    </div>}
    <div className="hero-index"><span>ULUCAN</span><b>SAHA</b></div>
  </section>;
}
